// src/context/AuthContext.js
import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { authAPI } from '../api/services';
import toast from 'react-hot-toast';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [user, setUser]       = useState(null);
  const [loading, setLoading] = useState(true);  // stays true until session is resolved

  // Restore session on mount — MUST finish before any route renders
  useEffect(() => {
    const token = localStorage.getItem('accessToken');
    if (!token) {
      setLoading(false);
      return;
    }
    authAPI.me()
      .then(({ data }) => {
        const u = data.employee || data.user || data;
        setUser(u);
      })
      .catch(() => {
        // Token invalid / expired and refresh failed — clear everything
        localStorage.removeItem('accessToken');
        localStorage.removeItem('refreshToken');
        setUser(null);
      })
      .finally(() => setLoading(false));
  }, []);

  const login = useCallback(async (email, password) => {
    const { data } = await authAPI.login({ email, password });

    console.log('🔑 RAW LOGIN RESPONSE:', JSON.stringify(data, null, 2));

    // Try every common token key name backends use
    const accessToken  = data.accessToken  || data.access_token  || data.token        || data.jwt;
    const refreshToken = data.refreshToken || data.refresh_token || data.refreshToken || '';
    const profile      = data.employee     || data.user          || data.profile       || null;

    console.log('🔑 accessToken found:', accessToken ? accessToken.substring(0,30)+'...' : 'NOT FOUND');
    console.log('👤 profile found:', profile);

    if (!accessToken) {
      throw new Error('No access token in response. Check console for raw response shape.');
    }

    // 1. Persist tokens FIRST
    localStorage.setItem('accessToken',  accessToken);
    localStorage.setItem('refreshToken', refreshToken);

    // 2. Prefer embedded profile in login response; fall back to /me
    let userProfile = profile;
    if (!userProfile) {
      try {
        const me = await authAPI.me();
        userProfile = me.data.employee || me.data.user || me.data;
        console.log('👤 profile from /me:', userProfile);
      } catch {
        userProfile = { email };
      }
    }

    // 3. Set user in state
    setUser(userProfile);
    return data;
  }, []);

  const logout = useCallback(() => {
    localStorage.removeItem('accessToken');
    localStorage.removeItem('refreshToken');
    setUser(null);
    toast.success('Logged out successfully');
  }, []);

  const changePassword = useCallback(async (currentPassword, newPassword) => {
    await authAPI.changePassword({ currentPassword, newPassword });
  }, []);

  return (
    <AuthContext.Provider value={{ user, loading, login, logout, changePassword }}>
      {children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be inside AuthProvider');
  return ctx;
};
